@app.route('/moderate_data', methods=['POST'])
def moderate_data():
    """Endpoint for trusted moderators to approve quarantined data"""
    try:
        moderator_id = request.form.get('moderator_id')
        file_hash = request.form.get('file_hash')
        action = request.form.get('action')  # 'approve' or 'reject'
        
        if moderator_id not in TRUSTED_MODERATORS:
            return jsonify({'error': 'Unauthorized'}), 403
        
        quarantine_path = os.path.join(app.config['UPLOAD_FOLDER'], 'quarantine', f'{file_hash}.json')
        
        if not os.path.exists(quarantine_path):
            return jsonify({'error': 'Data not found'}), 404
        
        with open(quarantine_path, 'r') as f:
            metadata = json.load(f)
        
        user_id = metadata['user_id']
        
        if action == 'approve':
            # Increase user reputation
            if user_id in user_contributions:
                user_contributions[user_id]['reputation'] = min(1.0, user_contributions[user_id]['reputation'] + 0.2)
            metadata['status'] = 'approved'
            metadata['moderator'] = moderator_id
            
        elif action == 'reject':
            # Decrease user reputation and potentially flag
            if user_id in user_contributions:
                user_contributions[user_id]['reputation'] *= 0.5
                if user_contributions[user_id]['reputation'] < 0.3:
                    flagged_users.add(user_id)
            metadata['status'] = 'rejected'
            metadata['moderator'] = moderator_id
        
        with open(quarantine_path, 'w') as f:
            json.dump(metadata, f)
        
        return jsonify({
            'status': 'success',
            'action': action,
            'user_reputation': user_contributions.get(user_id, {}).get('reputation', 0)
        }), 200
        
    except Exception as e:
        logger.error(f"Error in moderation: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

